// The previous attempt's bare `assert(post1_netc.my_end_point() ==
// pre_netc.my_end_point())` failed because the per-run ensures
// (H1, H2) are the *antecedent* of the implication in the ensures
// of `det_<f>` — they are NOT free hypotheses inside the body.
//
// The repair is structural: a single `if (H1 && H2) { ... }` block.
// Inside that branch, Verus places H1 ∧ H2 into the proof context,
// so every `assert(X)` we discharge there is sound; outside the
// branch each such assertion becomes the conditional fact
// `(H1 && H2) ==> X`, which is exactly the shape Verus needs to
// stitch together when discharging the `(H1 && H2) ==> det_equal`
// ensures.  Inside we additionally case-split on the joint variant
// (r1.0-tag, r2.0-tag) so the two per-run `==>` arms of H1 and H2
// unfold on aligned triggers (the original `unknown` came from z3
// never lining up the r1- and r2- arms of `rr is Packet ==> ...`
// because they bound disjoint `net_event` witnesses).

if ({
    &&& ({let (rr, net_event) = r1;
        &&& post1_netc.my_end_point() == pre_netc.my_end_point()
        &&& post1_netc.ok() == !(rr is Fail)
        &&& (!(rr is Fail) ==> post1_netc.ok() && post1_netc.history() == pre_netc.history() + seq!( net_event@ ))
        &&& (rr is Timeout ==> net_event@ is TimeoutReceive)
        &&& (rr is Packet ==> {
            &&& net_event@ is Receive
            &&& rr.arrow_Packet_cpacket().abstractable()
            &&& (!(rr.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(net_event@.arrow_Receive_r())
                &&& rr.arrow_Packet_cpacket().msg@ == sht_demarshal_data(net_event@.arrow_Receive_r().msg)@
            })
            &&& rr.arrow_Packet_cpacket().dst@ == local_addr@
        })
    })
    &&& ({let (rr, net_event) = r2;
        &&& post2_netc.my_end_point() == pre_netc.my_end_point()
        &&& post2_netc.ok() == !(rr is Fail)
        &&& (!(rr is Fail) ==> post2_netc.ok() && post2_netc.history() == pre_netc.history() + seq!( net_event@ ))
        &&& (rr is Timeout ==> net_event@ is TimeoutReceive)
        &&& (rr is Packet ==> {
            &&& net_event@ is Receive
            &&& rr.arrow_Packet_cpacket().abstractable()
            &&& (!(rr.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(net_event@.arrow_Receive_r())
                &&& rr.arrow_Packet_cpacket().msg@ == sht_demarshal_data(net_event@.arrow_Receive_r().msg)@
            })
            &&& rr.arrow_Packet_cpacket().dst@ == local_addr@
        })
    })
}) {
    // === H1 ∧ H2 in scope.  Re-assert each conjunct on aligned terms.
    //
    // r1 side.
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.ok() == !(r1.0 is Fail));
    // r2 side.
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.ok() == !(r2.0 is Fail));
    // Bridge through pre_netc: shared `my_end_point`, hence equal post
    // `my_end_point`s (the only pre-state-independent fact the
    // ensures expose).
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // Joint case-split on the variant tags of r1.0 and r2.0 so the
    // two per-run `rr is X ==> ...` arms of H1 and H2 unfold under
    // the same path condition.
    if r1.0 is Fail && r2.0 is Fail {
        // Both Fail: ok() = false on both, no history / cpacket facts.
        assert(!post1_netc.ok());
        assert(!post2_netc.ok());
        assert((r1.0 is Fail) == (r2.0 is Fail));
        assert((r1.0 is Timeout) == (r2.0 is Timeout));
        assert((r1.0 is Packet) == (r2.0 is Packet));
    } else if r1.0 is Timeout && r2.0 is Timeout {
        // Both Timeout: ok() = true, history extended by TimeoutReceive,
        // and the net_event view is TimeoutReceive on both runs.
        assert(post1_netc.ok());
        assert(post2_netc.ok());
        assert(r1.1@ is TimeoutReceive);
        assert(r2.1@ is TimeoutReceive);
        assert(post1_netc.history() == pre_netc.history() + seq!( r1.1@ ));
        assert(post2_netc.history() == pre_netc.history() + seq!( r2.1@ ));
        assert((r1.0 is Fail) == (r2.0 is Fail));
        assert((r1.0 is Timeout) == (r2.0 is Timeout));
        assert((r1.0 is Packet) == (r2.0 is Packet));
    } else if r1.0 is Packet && r2.0 is Packet {
        // Both Packet: ok() = true, history extended by Receive(...),
        // and each cpacket has its `dst` pinned at `local_addr@`.
        assert(post1_netc.ok());
        assert(post2_netc.ok());
        assert(r1.1@ is Receive);
        assert(r2.1@ is Receive);
        assert(r1.0->cpacket.abstractable());
        assert(r2.0->cpacket.abstractable());
        assert(r1.0->cpacket.dst@ == local_addr@);
        assert(r2.0->cpacket.dst@ == local_addr@);
        assert(r1.0->cpacket.dst@ == r2.0->cpacket.dst@);
        assert(post1_netc.history() == pre_netc.history() + seq!( r1.1@ ));
        assert(post2_netc.history() == pre_netc.history() + seq!( r2.1@ ));
        assert((r1.0 is Fail) == (r2.0 is Fail));
        assert((r1.0 is Timeout) == (r2.0 is Timeout));
        assert((r1.0 is Packet) == (r2.0 is Packet));
    } else {
        // Mixed variants: H1 / H2 each pin post-state `ok()` to the
        // per-run `!(rr is Fail)`, so a mixed Fail/non-Fail split
        // forces `post1_netc.ok() != post2_netc.ok()`.  Re-assert the
        // discriminator equalities to surface this contradiction on
        // aligned triggers.
        if r1.0 is Fail    { assert(!post1_netc.ok()); }
        if r1.0 is Timeout { assert(post1_netc.ok()); }
        if r1.0 is Packet  { assert(post1_netc.ok()); }
        if r2.0 is Fail    { assert(!post2_netc.ok()); }
        if r2.0 is Timeout { assert(post2_netc.ok()); }
        if r2.0 is Packet  { assert(post2_netc.ok()); }
    }
}
